INSERT INTO employees (first_name, last_name, email, phone, designation, department, joining_date, status, created_at, updated_at, deleted_at)
SELECT
    n.first_name,
    n.last_name,
    n.email,
    n.phone,
    n.designation,
    n.department,
    n.joining_date,
    n.emp_status,
